     1|export type OwnerLocationClarificationIntent = 'ambiguous_where_are_we' | 'physical_location_unavailable';
     2|
     3|export type IVXOwnerAISemanticIntent =
     4|  | 'time_query'
     5|  | 'ambiguous_location'
     6|  | 'physical_location_unavailable'
     7|  | 'project_status'
     8|  | 'long_structured_response'
     9|  | 'multi_step_task'
    10|  | 'deal_review'
    11|  | 'bug_review'
    12|  | 'code_retrieval'
    13|  | 'explicit_tool_request'
    14|  | 'app_build_planning'
    15|  | 'self_developer_execution'
    16|  | 'daily_self_improvement'
    17|  | 'media_generation_3d'
    18|  | 'normal_question';
    19|
    20|export type IVXOwnerAIRouteDecision = 'clarification' | 'time_tool' | 'tool_grounded_gpt' | 'self_developer' | 'self_improvement' | 'gpt_conversation';
    21|
    22|export type IVXOwnerAIPlannerDecision = {
    23|  semanticIntent: IVXOwnerAISemanticIntent;
    24|  route: IVXOwnerAIRouteDecision;
    25|  useTools: boolean;
    26|  toolHints: string[];
    27|  requiresLongResponse: boolean;
    28|  requiresTaskDecomposition: boolean;
    29|  memoryMode: 'load_recent_and_persist_turn';
    30|  fallbackPolicy: 'fail_visible_not_canned';
    31|  reason: string;
    32|};
    33|
    34|function normalizePrompt(prompt: string): string {
    35|  return prompt.trim().toLowerCase().replace(/\s+/g, ' ');
    36|}
    37|
    38|/**
    39| * Deterministic exact-echo command detector (acceptance test B).
    40| *
    41| * When the owner sends an explicit "reply/respond/say exactly: <X>" instruction,
    42| * IVX must return <X> VERBATIM — proving the LATEST owner message is the one being
    43| * executed, with no LLM paraphrasing, no clarification hijack, and no truncation.
    44| * Returns the exact text to echo (preserving original casing/characters), or null.
    45| */
    46|export function resolveExactEchoCommand(prompt: string): string | null {
    47|  const raw = prompt.trim();
    48|  if (!raw) {
    49|    return null;
    50|  }
    51|  // Match: reply/respond/answer/say/repeat/echo [back] exactly [with][:] <payload>
    52|  const match = raw.match(/^(?:please\s+)?(?:reply|respond|answer|say|repeat|echo|output|return|print)\s+(?:back\s+)?exactly(?:\s+with)?\s*[:\-]?\s*([\s\S]+)$/i);
    53|  if (!match) {
    54|    return null;
    55|  }
    56|  let payload = match[1].trim();
    57|  // Strip a single pair of wrapping quotes the owner may have added around the payload.
    58|  const quoted = payload.match(/^(["'\u201c\u2018])([\s\S]+)(["'\u201d\u2019])$/);
    59|  if (quoted) {
    60|    payload = quoted[2].trim();
    61|  }
    62|  return payload.length > 0 ? payload : null;
    63|}
    64|
    65|/**
    66| * Detects a long, structured owner EXECUTION command or task block (e.g.
    67| * "BLOCK 28 Visitor-to-Investor Conversion Engine / Create: ... / Track: ...").
    68| *
    69| * These must NEVER be hijacked by short clarification intents (physical location,
    70| * time, manual-answer, infrastructure-runtime) just because the spec happens to
    71| * mention a keyword like "location", "backend", or "runtime" inside a much larger
    72| * instruction. The whole class of "IVX answered the wrong context" bugs comes from
    73| * a clarification regex matching a single word inside a long command and short-
    74| * circuiting before execution routing. When this returns true, the planner routes
    75| * the command to task decomposition and the handler skips every clarification gate.
    76| */
    77|export function isOwnerExecutionOrTaskBlock(prompt: string): boolean {
    78|  const raw = prompt.trim();
    79|  if (!raw) {
    80|    return false;
    81|  }
    82|  const normalized = normalizePrompt(prompt);
    83|
    84|  // Explicit "BLOCK N" / "STEP N" / "PHASE N" task headers are always task blocks.
    85|  if (/\b(block|step|phase)\s*\d+\b/.test(normalized)) {
    86|    return true;
    87|  }
    88|
    89|  // Structured spec markers the owner uses for feature/task blocks.
    90|  const specMarkerCount = (raw.match(/^\s*(create|track|stages?|capabilities|dashboard|requirements?|safety|store|return|show|build|objective|audit|capabilities?|metrics?)\s*:/gim) ?? []).length;
    91|  if (specMarkerCount >= 2) {
    92|    return true;
    93|  }
    94|
    95|  // Multi-line, sufficiently long instructions are treated as task blocks so a
    96|  // single keyword can never reroute them to a one-line clarification answer.
    97|  const lineCount = raw.split(/\n/).filter((line) => line.trim().length > 0).length;
    98|  if (raw.length >= 320 && lineCount >= 4) {
    99|    return true;
   100|  }
   101|
   102|  // Imperative engine/system/feature build commands ("... Conversion Engine",
   103|  // "build the ... system") that are also reasonably long.
   104|  if (raw.length >= 90 && /\b(engine|system|pipeline|module|platform|dashboard|workflow)\b/.test(normalized) && /\b(create|build|implement|add|wire|ship|deploy|design|develop)\b/.test(normalized)) {
   105|    return true;
   106|  }
   107|
   108|  return false;
   109|}
   110|
   111|function asksForLongStructuredResponse(normalized: string): boolean {
   112|  return /\b(full\s+list|complete\s+list|list\s+all|enumerate|from\s+1\s+to\s+\d+|1\s*[-–to]+\s*\d+|one\s+to\s+\d+|\d{2,}\s+(?:items?|points?|things?|steps?|rows?|entries|checks?))\b/.test(normalized)
   113|    // Full / structured audits always need the long-response budget + auto-continuation.
   114|    || /\b(full\s+audit|complete\s+audit|end[-\s]?to[-\s]?end\s+audit|audit\s+(?:everything|all|end\s+to\s+end|one\s+by\s+one)|run\s+(?:a\s+)?full\s+audit|audit\s+\d{1,4}\s*[-–to]+\s*\d{1,4}|audit\s+from\s+1)\b/.test(normalized)
   115|    // Any explicit numeric range whose upper bound is large (e.g. "1-100", "1 to 2000").
   116|    || hasLargeExplicitRange(normalized);
   117|}
   118|
   119|export function hasLargeExplicitRange(normalized: string): boolean {
   120|  const match = normalized.match(/\b(?:from\s+)?1\s*(?:[-–]|to)\s*(\d{2,4})\b/);
   121|  if (match) {
   122|    const upper = Number.parseInt(match[1], 10);
   123|    return Number.isFinite(upper) && upper >= 30;
   124|  }
   125|  return false;
   126|}
   127|
   128|function asksForMultiStepTask(normalized: string): boolean {
   129|  return /\b(step[-\s]?by[-\s]?step|multi[-\s]?step|decompose|break\s+(?:it|this)?\s*down|task\s+decomposition|execution\s+plan|implementation\s+plan|roadmap|sequence)\b/.test(normalized)
   130|    || /\b(build|fix|audit|implement|ship|repair|improve)\b.{0,80}\b(plan|steps|phases|tasks)\b/.test(normalized);
   131|}
   132|
   133|export function asksForDealReview(normalized: string): boolean {
   134|  return /\b(review\s+(?:this\s+)?deal|deal\s+review|underwrite|underwriting|cap\s+rate|noi|cash[-\s]?on[-\s]?cash|real\s+estate\s+deal|investment\s+deal)\b/.test(normalized);
   135|}
   136|
   137|export function asksForBugReview(normalized: string): boolean {
   138|  return /\b(what\s+bugs?\s+do\s+you\s+see|find\s+bugs?|bug\s+review|bug\s+list|prioritized\s+bug\s+list|review\s+(?:the\s+)?bugs?|errors?\s+do\s+you\s+see|what\s+is\s+broken)\b/.test(normalized)
   139|    || /\binspect\b.{0,100}\b(?:chat|ai|assistant)\b.{0,100}\bbugs?\b/.test(normalized);
   140|}
   141|
   142|/**
   143| * Detects when the owner wants to SEE real source code from the repository —
   144| * file paths, functions, endpoints, queries, or a feature's implementation —
   145| * rather than execute a build/fix task. These requests must be grounded in the
   146| * live repo (code search) so the answer contains concrete files and source,
   147| * never a generic LLM guess or a clarification question.
   148| */
   149|export function asksForCodeRetrieval(normalized: string): boolean {
   150|  const codeNoun = /\b(code|source|source\s+code|snippet|implementation|function|method|class|file|files|file\s+path|endpoint|route|api\s+route|handler|query|queries|sql\s+quer(?:y|ies)|service|module|component|schema\s+definition)\b/;
   151|  const retrievalVerb = /\b(show|give|return|see|read|display|paste|get|list|find|reveal|provide|where\s+is|which\s+file|what\s+file|locate|share)\b/;
   152|  // "show me the analytics code", "return the analytics implementation", "where is the auth endpoint"
   153|  if (retrievalVerb.test(normalized) && codeNoun.test(normalized)) {
   154|    return true;
   155|  }
   156|  // Direct phrasings that always imply real code retrieval.
   157|  return /\b(source\s+code|code\s+for|implementation\s+of|implementation\s+details|actual\s+code|real\s+code|how\s+is\s+\w+\s+implemented|how\s+does\s+\w+\s+work\s+in\s+(?:the\s+)?code|file\s+path|function\s+name|endpoint\s+definition|database\s+quer(?:y|ies)\s+used)\b/.test(normalized);
   158|}
   159|
   160|/**
   161| * Detects open-ended app/product build requests like "build an app like TikTok",
   162| * "create a clone of Uber", "I want to build a marketplace app". These must NOT
   163| * fall through to a generic conversational timeline. They trigger a senior product-
   164| * engineering planning response: architecture proposal, module breakdown, required
   165| * repo/actions, execution plan, and a permission/capability check — not boilerplate.
   166| *
   167| * Deliberately excludes prompts that already point at THIS repo's concrete work
   168| * ("build the feature", "build this screen"), which belong to self-developer execution.
   169| */
   170|/**
   171| * Detects an owner request to GENERATE a 3D model / mesh / render (e.g.
   172| * "generate a 3d model of a villa", "create a 3D render of our product",
   173| * "make me a 3d mesh of a chair"). Routes to the owner 3D generation tool
   174| * (Meshy/Tripo direct, or a deterministic procedural Three.js preview).
   175| *
   176| * Deliberately excludes "build an app" / generic build requests by requiring an
   177| * explicit 3D/mesh/render target word.
   178| */
   179|export function asksToGenerate3DModel(normalized: string): boolean {
   180|  const genVerb = /\b(generate|create|make|build|render|design|produce|model|sculpt|give\s+me|i\s+want|i\s+need)\b/;
   181|  const threeDTarget = /\b(3d|three[\s-]?d)\b/;
   182|  const meshTarget = /\b(3d\s+model|3d\s+render|3d\s+mesh|3d\s+object|3d\s+asset|mesh|render)\b/;
   183|  if (!genVerb.test(normalized)) {
   184|    return false;
   185|  }
   186|  if (threeDTarget.test(normalized)) {
   187|    return true;
   188|  }
   189|  // "model/mesh/render" without "3d" only counts when paired with a clear object word.
   190|  return meshTarget.test(normalized) && /\b(model|mesh|render|object|asset|figure|statue|product|prototype|scene)\b/.test(normalized);
   191|}
   192|
   193|export function asksToBuildApp(normalized: string): boolean {
   194|  // "build/create/make/design/develop ... an/a/another ... app/clone/platform/product/mvp/saas/marketplace/..."
   195|  const buildVerb = /\b(build|create|make|design|develop|spin\s+up|launch|clone|ship)\b/;
   196|  const appNoun = /\b(app|application|clone|platform|product|mvp|saas|marketplace|startup|website|web\s+app|mobile\s+app|social\s+(?:app|network|platform)|dating\s+app|delivery\s+app|fintech\s+app)\b/;
   197|  // "like X" / "such as X" / "similar to X" / "version of X" / "clone of X" strongly implies product planning.
   198|  const comparativeApp = /\b(?:app|clone|platform|product|version|something)\b[^.]{0,40}\b(?:like|similar\s+to|such\s+as)\b/;
   199|  const cloneOf = /\b(clone|version|copy)\s+of\s+\w+/;
   200|
   201|  // A build command aimed at the owner's OWN IVX system ("build the IVX engine",
   202|  // "create our investment platform", "finish the autonomous engine") is in-repo
   203|  // EXECUTION, not a request to scaffold a brand-new external product. It must never
   204|  // enter narrative "app planning" mode — it routes to the senior-developer runtime.
   205|  if (targetsOwnSystemBuild(normalized)) {
   206|    return false;
   207|  }
   208|  if (cloneOf.test(normalized) || comparativeApp.test(normalized)) {
   209|    return true;
   210|  }
   211|  if (buildVerb.test(normalized) && appNoun.test(normalized)) {
   212|    // Avoid hijacking concrete in-repo execution like "build the screen"/"build this feature".
   213|    const pointsAtThisRepoWork = /\b(this|that|the)\s+(feature|screen|fix|bug|endpoint|route|module|component|migration|page|function|test)\b/.test(normalized);
   214|    return !pointsAtThisRepoWork;
   215|  }
   216|  return false;
   217|}
   218|
   219|/**
   220| * Detects a build/execute command aimed at the owner's OWN IVX system rather than a
   221| * brand-new external app. These are concrete in-repo engineering jobs ("build the IVX
   222| * autonomous engine", "create our investor pipeline", "finish the conversion engine",
   223| * "implement the IVX dashboard module") and must EXECUTE end-to-end via the senior-
   224| * developer runtime — never get answered with an "Architecture Proposal / Phase 1-4"
   225| * narrative. The signal is a build verb plus either an explicit "IVX"/"our"/"my"
   226| * possessive or a system-component noun (engine, pipeline, module, workflow, dashboard,
   227| * system, platform) describing THIS product.
   228| */
   229|export function targetsOwnSystemBuild(normalized: string): boolean {
   230|  const buildVerb = /\b(build|create|implement|develop|add|wire|integrate|set\s*up|spin\s*up|ship|deploy|launch|configure|finish|complete|make|design|generate|code)\b/;
   231|  if (!buildVerb.test(normalized)) {
   232|    return false;
   233|  }
   234|  // Explicit reference to THIS product / owner's own system.
   235|  const ownProduct = /\bivx\b/.test(normalized)
   236|    || /\b(our|my|the)\s+(?:own\s+)?(?:autonomous\s+|investment\s+|global\s+|owner\s+)?(engine|pipeline|module|workflow|dashboard|system|platform|backend|api|app|product|crm|portal)\b/.test(normalized);
   237|  // System-component nouns that, paired with a build verb, mean in-repo execution.
   238|  const systemComponent = /\b(engine|pipeline|module|workflow|conversion\s+engine|investment\s+engine|autonomous\s+(?:engine|system|investment))\b/.test(normalized);
   239|  return ownProduct || systemComponent;
   240|}
   241|
   242|/**
   243| * Detects work-completion / "prove you are a senior developer" requests, e.g.
   244| * "finish and show proof you are a senior developer", "complete the task and prove it",
   245| * "act as a senior developer and finish this". These are engineering-execution
   246| * intents and must route to the senior-developer runtime — NEVER to a canned
   247| * audit/status report (the word "developer" + "proof"/"code" must not be misread
   248| * as an IVX free/control audit).
   249| */
   250|export function asksToFinishOrProveSeniorDeveloperWork(normalized: string): boolean {
   251|  // "finish and show proof / deploy / prove / push ...", "finish it/this/the task/now".
   252|  const finishWork = /\b(finish|finalize|finalise|wrap\s+up|complete|deliver)\b.{0,60}\b(it|this|that|task|job|work|build|feature|fix|deployment|deploy|code|implementation|now|today|and\s+(?:show|deploy|prove|push|test|verify|ship|finish|complete))\b/i.test(normalized)
   253|    || /\bfinish\s+and\b/i.test(normalized);
   254|  // "(act as|be|prove you are|show proof you are|you are) a senior developer/engineer".
   255|  const seniorDeveloperPersona = /\b(?:act\s+as|be|prove\s+(?:you\s+are|that\s+you\s+are|yourself)|show\s+(?:me\s+)?proof\s+(?:you\s+are|that\s+you\s+are)|demonstrate\s+(?:you\s+are|that\s+you\s+are)|you\s+are)\s+(?:a\s+)?(?:real\s+|true\s+)?senior\s+(?:software\s+)?(?:developer|engineer|dev)\b/i.test(normalized)
   256|    || /\bsenior\s+(?:software\s+)?(?:developer|engineer)\b.{0,40}\b(mode|now|finish|complete|execute|work|build|fix|deploy|prove|show\s+proof|do\s+it)\b/i.test(normalized);
   257|  return finishWork || seniorDeveloperPersona;
   258|}
   259|
   260|/**
   261| * Detects the owner's daily self-improvement command — the single entry point that
   262| * starts the autonomous "find issue → patch → test → commit → deploy → verify" loop
   263| * WITHOUT naming a specific file or bug. Phrasings: "improve IVX today", "fix one bug
   264| * today", "self improve", "run daily improvement". These must route to the dedicated
   265| * daily-improvement task so progress is durable + visible in the Live Developer Monitor,
   266| * never to a generic conversational answer.
   267| */
   268|export function asksToImproveIVXToday(prompt: string): boolean {
   269|  const normalized = normalizePrompt(prompt);
   270|  if (!normalized) {
   271|    return false;
   272|  }
   273|  return /\bimprove\s+ivx(?:\s+(?:today|now|daily|automatically))?\b/.test(normalized)
   274|    || /\b(?:run|start|kick\s*off|begin)\s+(?:the\s+|a\s+)?daily\s+(?:self[-\s]?)?improvement\b/.test(normalized)
   275|    || /\bdaily\s+self[-\s]?improvement\b/.test(normalized)
   276|    || /\bself[-\s]?improve(?:ment)?\b/.test(normalized)
   277|    || /\bfix\s+one\s+(?:real\s+)?(?:bug|issue|problem)(?:\s+(?:today|now))?\b/.test(normalized)
   278|    || /\bimprove\s+(?:the\s+)?(?:platform|app|system|codebase|product)\s+(?:today|now|daily|automatically)\b/.test(normalized);
   279|}
   280|
   281|/**
   282| * Detects the owner's opportunity-discovery command — "find today's best opportunity",
   283| * "best opportunity today", "find me an opportunity", "opportunity scan", "scan for
   284| * opportunities". Routes to the owner-gated Opportunity Intelligence Engine so the
   285| * answer is grounded in real scored opportunities (never a fabricated tip).
   286| */
   287|export function asksForBestOpportunity(prompt: string): boolean {
   288|  const normalized = normalizePrompt(prompt);
   289|  if (!normalized) {
   290|    return false;
   291|  }
   292|  return /\bfind\s+(?:me\s+|today'?s\s+|the\s+)?(?:best|top|highest[-\s]?upside)\s+(?:opportunit(?:y|ies)|deal|investment)\b/.test(normalized)
   293|    || /\b(?:best|top|highest[-\s]?upside)\s+opportunit(?:y|ies)\s+(?:today|now|right\s+now)\b/.test(normalized)
   294|    || /\b(?:today'?s\s+)?(?:best|top)\s+opportunit(?:y|ies)\b/.test(normalized)
   295|    || /\b(?:run|start|do)\s+(?:an?\s+)?opportunity\s+scan\b/.test(normalized)
   296|    || /\bscan\s+(?:for|the\s+market\s+for)\s+opportunit(?:y|ies)\b/.test(normalized)
   297|    || /\bfind\s+(?:me\s+)?(?:an?\s+)?opportunit(?:y|ies)\b/.test(normalized);
   298|}
   299|
   300|/**
   301| * Detects the owner's "find the best investor for Deal X" command — routes to the
   302| * BLOCK 27 best-investor workflow (search CRM → rank → draft intro → follow-up →
   303| * log → proof). Distinct from `asksForBestOpportunity` (which finds DEALS, not
   304| * investors). Matches "find the best investor for Casa Rosario", "who is the best
   305| * investor for deal X", "best buyer/investor for <deal>", "match investors to X".
   306| */
   307|export function asksToFindBestInvestor(prompt: string): boolean {
   308|  const normalized = normalizePrompt(prompt);
   309|  if (!normalized) {
   310|    return false;
   311|  }
   312|  return /\b(?:find|get|show|who(?:'?s| is| are)?)\s+(?:me\s+|us\s+|the\s+)?(?:best|top|right|ideal)\s+investors?\s+for\b/.test(normalized)
   313|    || /\b(?:best|top|right|ideal)\s+investors?\s+for\s+(?:the\s+)?(?:deal|project|property|opportunity)\b/.test(normalized)
   314|    || /\bmatch\s+investors?\s+(?:to|for|with)\b/.test(normalized)
   315|    || /\bfind\s+(?:me\s+)?(?:the\s+)?(?:best|top|right|ideal)\s+(?:investor|buyer|backer|capital)\s+for\b/.test(normalized)
   316|    || /\bwho\s+should\s+(?:i|we)\s+(?:pitch|approach|contact|raise\s+from)\s+for\b/.test(normalized);
   317|}
   318|
   319|/**
   320| * Detects the owner demanding EXECUTION + PROOF instead of a narrative report — e.g.
   321| * "audit end to end and fix and deploy and prove verified", "stop narrative, fix this
   322| * now", "no more narrative, deploy and verify". This is the exact class of command that
   323| * was wrongly routed to a long narrative audit: the words "end to end audit" set
   324| * `requiresLongResponse = true`, which gated OFF the execute path, so the command fell
   325| * through to `long_structured_response` (the narrative the owner keeps rejecting).
   326| *
   327| * When this returns true the planner routes to the senior-developer runtime so IVX
   328| * EXECUTES (inspect → patch → test → commit → deploy → verify) and returns live proof,
   329| * never a narrative — even when an "audit" word is present in the same message.
   330| */
   331|export function demandsExecutionProofNotNarrative(normalized: string): boolean {
   332|  // Explicit "stop / no / no more / without narrative" always forces execution.
   333|  const banNarrative = /\b(?:no|stop|not|without|don'?t\s+(?:give|want|send|do)|kill|skip|cut|enough|no\s+more)\b[^.]{0,30}\bnarrativ\w*/.test(normalized)
   334|    || /\bnarrativ\w*\b[^.]{0,30}\b(?:stop|off|no\s+more|enough|kill)\b/.test(normalized);
   335|  if (banNarrative) {
   336|    return true;
   337|  }
   338|  // An audit/verify/review/check request PAIRED with a real execute/ship/prove demand
   339|  // means "do the work and prove it", not "write me a report".
   340|  const mentionsAudit = /\b(audit|verify|verified|verification|review|check|prove|proof|end[-\s]?to[-\s]?end|finish|complete)\b/.test(normalized);
   341|  const demandsAction = /\b(fix|patch|repair|deploy|redeploy|ship|release|push|implement|build|execute|run|remove|delete|eliminate|clean\s*up|clear|get\s+rid\s+of|make\s+it\s+work|get\s+it\s+(?:done|working|fixed|shipped|deployed|live)|live\s+deploy|deploy\s+live|go\s+live|prove\s+(?:it|verified)|show\s+proof)\b/.test(normalized);
   342|  return mentionsAudit && demandsAction;
   343|}
